eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   ARTICLES: () => (/* binding */ ARTICLES)\n/* harmony export */ });\nconst ARTICLES = [\n    {\n        id: 1,\n        title: \"۵ نشانه که به زوج‌درمانی نیاز دارید\",\n        excerpt: \"بسیاری از زوج‌ها صبر می‌کنند تا مشکلات عمیق‌تر شود. این مقاله نشانه‌های هشداردهنده را توضیح می‌دهد.\",\n        category: \"زوج‌درمانی\",\n        readTime: \"۵ دقیقه\",\n        date: \"۱۴۰۳/۰۴/۱۵\",\n        slug: \"signs-need-couple-therapy\",\n        metaDesc: \"آیا رابطه شما به کمک نیاز دارد؟ ۵ نشانه مهم که نشان می‌دهد وقت مراجعه به زوج‌درمانگر رسیده. مقاله علمی از دکتر هما آزادی، روان‌شناس اصفهان.\",\n        intro: \"یکی از بزرگ‌ترین اشتباهاتی که زوج‌ها مرتکب می‌شوند این است که خیلی دیر به زوج‌درمانی مراجعه می‌کنند. تحقیقات نشان می‌دهد زوج‌ها به طور متوسط ۶ سال بعد از شروع مشکلات جدی به درمانگر مراجعه می‌کنند. در این مدت مشکلات ریشه می‌دوانند، الگوهای مخرب تثبیت می‌شوند و آسیب‌های عاطفی انباشته می‌شوند. شناخت نشانه‌های اولیه می‌تواند این مسیر را کوتاه‌تر کند.\",\n        sections: [\n            {\n                heading: \"۱. دعواها تکراری هستند و هیچ‌وقت حل نمی‌شوند\",\n                body: \"اگر متوجه شده‌اید که همان بحث‌ها بارها و بارها تکرار می‌شوند — با همان کلمات، همان عصبانیت و همان نتیجه — این یک نشانه جدی است. دعوای تکراری نشان می‌دهد الگوی ارتباطی ثابتی شکل گرفته که بدون کمک تخصصی تغییر نخواهد کرد. درمانگر می‌تواند این الگو را شکست دهد و روش‌های جدید گفتگو را به شما یاد بدهد.\"\n            },\n            {\n                heading: \"۲. احساس می‌کنید با غریبه‌ای زندگی می‌کنید\",\n                body: \"فاصله عاطفی یکی از خطرناک‌ترین نشانه‌هاست؛ چون بر خلاف دعوا، بی‌سر و صدا است. وقتی دیگر درباره احساسات، روز، ترس‌ها و رویاهایتان صحبت نمی‌کنید — وقتی همسرتان از بهترین دوست به هم‌اتاقی تبدیل شده — رابطه در حال مرگ آهسته است. زوج‌درمانی می‌تواند این صمیمیت از دست رفته را بازگرداند.\"\n            },\n            {\n                heading: \"۳. تحقیر، بی‌احترامی یا خاموشی در رابطه وجود دارد\",\n                body: \"جان گاتمن، روان‌شناس برجسته، چهار رفتار را \\xabسواران آخرالزمان\\xbb رابطه می‌نامد: انتقاد، تحقیر، موضع دفاعی و خاموشی (قطع ارتباط در حین دعوا). حضور هر یک از این رفتارها — به خصوص تحقیر — نشانه‌ای است که بدون مداخله متخصص، رابطه آسیب جدی خواهد دید. خوش‌بختانه این الگوها قابل تغییر هستند.\"\n            },\n            {\n                heading: \"۴. بحران‌های خارجی رابطه را به هم ریخته\",\n                body: \"بحران‌هایی مانند خیانت، از دست دادن شغل، مشکلات مالی، فوت یکی از اعضای خانواده یا بیماری جدی می‌توانند حتی محکم‌ترین روابط را تحت فشار بگذارند. در این مواقع انتظار ندارید که به تنهایی از پس این بحران بربیایید. کمک گرفتن نشانه هوشمندی است، نه ضعف.\"\n            },\n            {\n                heading: \"۵. فکر جدایی دائماً در ذهنتان است\",\n                body: \"اگر طلاق یا جدایی به یک فکر مکرر تبدیل شده — حتی اگر هنوز تصمیم نگرفته‌اید — این نشانه‌ای است که رابطه نیاز جدی به توجه دارد. بسیاری از زوج‌هایی که در این مرحله به درمانگر مراجعه می‌کنند، موفق به بازسازی رابطه می‌شوند. حتی اگر تصمیم به جدایی بگیرند، درمانگر کمک می‌کند این مرحله را سالم‌تر طی کنند.\"\n            }\n        ],\n        conclusion: \"مراجعه زودتر به زوج‌درمانگر، نتایج بهتری در پی دارد. اگر حتی یکی از این نشانه‌ها را در رابطه‌تان می‌بینید، این می‌تواند زمان مناسبی برای اولین قدم باشد. زوج‌درمانی نه پایان رابطه، بلکه شروع دوباره آن است.\",\n        relatedSlugs: [\n            \"why-premarital-counseling-matters\",\n            \"7-communication-skills-couples\"\n        ]\n    },\n    {\n        id: 2,\n        title: \"مشاوره پیش از ازدواج: چرا مهم است؟\",\n        excerpt: \"آمادگی پیش از ازدواج می‌تواند پایه‌های یک زندگی مشترک سالم را بسازد. بدانید چرا این قدم مهم است.\",\n        category: \"پیش از ازدواج\",\n        readTime: \"۷ دقیقه\",\n        date: \"۱۴۰۳/۰۴/۰۱\",\n        slug: \"why-premarital-counseling-matters\",\n        metaDesc: \"چرا مشاوره پیش از ازدواج مهم است؟ آنچه در جلسات بررسی می‌شود و چگونه می‌تواند از طلاق جلوگیری کند. مقاله دکتر هما آزادی.\",\n        intro: \"ازدواج مهم‌ترین تصمیم زندگی بسیاری از افراد است. با این حال، بیشتر زوج‌ها ماه‌ها وقت صرف برنامه‌ریزی مراسم عروسی می‌کنند اما ساعتی برای آمادگی برای زندگی مشترک اختصاص نمی‌دهند. مشاوره پیش از ازدواج این شکاف را پر می‌کند و می‌تواند پایه‌های یک زندگی مشترک سالم را بسازد.\",\n        sections: [\n            {\n                heading: \"تفاوت \\xabعاشق هم بودن\\xbb با \\xabبرای زندگی مشترک آماده بودن\\xbb\",\n                body: \"عشق شرط لازم ازدواج است اما کافی نیست. زوج‌های زیادی که عمیقاً عاشق هم بودند به مشکلات جدی خوردند چون درباره مسائل اساسی صحبت نکرده بودند: چه کسی هزینه‌ها را مدیریت می‌کند؟ کجا زندگی می‌کنیم؟ نقش خانواده‌های طرفین چقدر است؟ فرزند می‌خواهیم؟ چه ارزش‌های دینی یا فرهنگی داریم؟ مشاوره پیش از ازدواج این سؤالات را قبل از ازدواج مطرح می‌کند، نه بعد از آن.\"\n            },\n            {\n                heading: \"آنچه در جلسات مشاوره پیش از ازدواج بررسی می‌شود\",\n                body: \"جلسات معمولاً موضوعات زیر را پوشش می‌دهند: ارتباط و حل تعارض (چگونه با هم اختلاف نظر را حل می‌کنید؟)؛ امور مالی (درآمد، هزینه، پس‌انداز و بدهی)؛ فرزندآوری و سبک تربیت فرزند؛ روابط با خانواده‌های طرفین؛ اهداف و ارزش‌های زندگی؛ صمیمیت عاطفی و جنسی؛ و بررسی سبک‌های دلبستگی. هر موضوع با استفاده از ابزارهای معتبر روان‌شناختی ارزیابی می‌شود.\"\n            },\n            {\n                heading: \"آزمون PREPARE/ENRICH چیست؟\",\n                body: \"PREPARE/ENRICH یکی از معتبرترین ابزارهای علمی دنیا برای ارزیابی آمادگی زوجین قبل از ازدواج است. این آزمون در بیش از ۵۰ کشور استفاده می‌شود و دهه‌ها تحقیق علمی پشت آن است. نتایج آن نقاط قوت رابطه و حوزه‌هایی که نیاز به توجه دارند را مشخص می‌کند. در مرکز دکتر آزادی، این آزمون بخشی از برنامه مشاوره پیش از ازدواج است.\"\n            },\n            {\n                heading: \"آیا مشاوره پیش از ازدواج به معنای مشکل در رابطه است؟\",\n                body: \"خیر. مشاوره پیش از ازدواج مانند معاینه پزشکی است — شما برای بیمار بودن به پزشک نمی‌روید، برای حفظ سلامت می‌روید. بسیاری از زوج‌هایی که مشاوره پیش از ازدواج می‌گیرند رابطه سالمی دارند و فقط می‌خواهند سالم‌تر شروع کنند. این آگاهی و پیشگیری، بسیار باهوشانه‌تر از انتظار برای بروز بحران است.\"\n            },\n            {\n                heading: \"چقدر طول می‌کشد و چه زمانی شروع کنیم؟\",\n                body: \"ایده‌آل این است که ۳ تا ۶ ماه قبل از ازدواج شروع کنید. تعداد جلسات بسته به نیاز زوج معمولاً بین ۴ تا ۸ جلسه است. حتی اگر تاریخ عروسی نزدیک است، دریافت حتی ۲ تا ۳ جلسه هم می‌تواند دیدگاه‌های ارزشمندی ارائه دهد.\"\n            }\n        ],\n        conclusion: \"مشاوره پیش از ازدواج یک سرمایه‌گذاری است — سرمایه‌گذاری در سالم‌ترین و مهم‌ترین رابطه زندگی‌تان. اگر به ازدواج فکر می‌کنید، این قدم را جدی بگیرید. آینده زندگی مشترک شما از همین تصمیم‌های امروز ساخته می‌شود.\",\n        relatedSlugs: [\n            \"signs-need-couple-therapy\",\n            \"7-communication-skills-couples\"\n        ]\n    },\n    {\n        id: 3,\n        title: \"وسواس فکری: باورهای غلط که باید بدانید\",\n        excerpt: \"OCD یک اختلال قابل درمان است. در این مقاله سوءتفاهم‌های رایج درباره وسواس را برطرف می‌کنیم.\",\n        category: \"درمان وسواس\",\n        readTime: \"۶ دقیقه\",\n        date: \"۱۴۰۳/۰۳/۲۰\",\n        slug: \"ocd-myths-facts\",\n        metaDesc: \"باورهای غلط رایج درباره وسواس فکری و عملی (OCD). واقعیت‌های علمی درباره درمان وسواس. مقاله دکتر هما آزادی، روان‌شناس اصفهان.\",\n        intro: \"وسواس فکری-عملی (OCD) یکی از سوءتفاهم‌شده‌ترین اختلالات روان‌پزشکی است. بسیاری از افراد مبتلا سال‌ها با شرم و پنهان‌کاری زندگی می‌کنند چون تصویر درستی از این اختلال ندارند. در این مقاله رایج‌ترین باورهای غلط را با واقعیت‌های علمی مقایسه می‌کنیم.\",\n        sections: [\n            {\n                heading: \"باور غلط ۱: وسواس یعنی تمیزکاری افراطی\",\n                body: \"رایج‌ترین تصویر از OCD در رسانه‌ها، فردی است که مدام دستانش را می‌شوید. اما OCD اشکال بسیار متنوع‌تری دارد: وسواس بررسی (چک کردن مکرر در، گاز یا اتو)؛ وسواس تقارن و نظم؛ وسواس افکار مزاحم درباره آسیب رساندن به خود یا دیگران؛ وسواس مذهبی و گناه؛ وسواس‌های مربوط به روابط. بسیاری از افراد مبتلا به OCD هیچ ربطی به نظافت ندارند.\"\n            },\n            {\n                heading: \"باور غلط ۲: OCD یعنی فرد \\xabوسواسی\\xbb است و این ویژگی شخصیتی است\",\n                body: \"وقتی کسی می‌گوید \\xabخیلی OCD هستم\\xbb یعنی دقیق و منظم است — این استفاده از OCD به عنوان صفت شخصیتی، به افراد واقعاً مبتلا آسیب می‌زند. OCD یک اختلال روان‌پزشکی مشخص با معیارهای تشخیصی دقیق است، نه ویژگی شخصیتی. افراد مبتلا اغلب از افکار مزاحم خود رنج می‌برند و آن‌ها را نمی‌خواهند — این دقیقاً برعکس \\xabتمیز و منظم بودن\\xbb است.\"\n            },\n            {\n                heading: \"باور غلط ۳: OCD درمان ندارد\",\n                body: \"OCD یکی از قابل‌درمان‌ترین اختلالات روان‌شناختی است. روش ERP (مواجهه و جلوگیری از پاسخ) که نوعی از درمان شناختی-رفتاری است، در تحقیقات متعدد اثربخشی بسیار بالایی نشان داده. اکثر بیماران با درمان مناسب بهبود قابل توجهی تجربه می‌کنند و می‌توانند زندگی عادی داشته باشند.\"\n            },\n            {\n                heading: \"باور غلط ۴: باید با اراده بیشتر وسواس را کنترل کنم\",\n                body: \"OCD یک اختلال عصبی-زیستی است که با ساختار و عملکرد مغز مرتبط است. از فرد دیابتیک نمی‌خواهیم با اراده بیشتر انسولین تولید کند — از فرد مبتلا به OCD هم نمی‌توان انتظار داشت فقط با اراده، مغزش را تغییر دهد. درمان تخصصی ضروری است.\"\n            },\n            {\n                heading: \"باور غلط ۵: افکار مزاحم OCD یعنی فرد بدی هستم\",\n                body: \"یکی از دردناک‌ترین جنبه‌های OCD، افکار مزاحم درباره آسیب رساندن، گناه یا موضوعات ممنوعه است. این افکار دقیقاً برعکس ارزش‌های فرد هستند و به همین دلیل آنقدر آزاردهنده‌اند. وجود این افکار نشانه بدی شخصیت نیست — نشانه OCD است. افراد سالم هم گاهی افکار عجیب دارند اما آن‌ها را جدی نمی‌گیرند؛ مبتلا به OCD گیر این افکار می‌افتد.\"\n            }\n        ],\n        conclusion: \"اگر یا یکی از عزیزانتان با علائمی شبیه به OCD دست و پنجه نرم می‌کنید، بدانید که کمک گرفتن ممکن است و موثر است. با یک متخصص صحبت کنید — این اولین و مهم‌ترین قدم است.\",\n        relatedSlugs: [\n            \"managing-anxiety-in-family\",\n            \"signs-need-couple-therapy\"\n        ]\n    },\n    {\n        id: 4,\n        title: \"ارتباط سالم: ۷ مهارتی که هر زوجی باید بداند\",\n        excerpt: \"ارتباط مؤثر یکی از مهم‌ترین عوامل موفقیت در زندگی مشترک است. این مهارت‌ها را یاد بگیرید.\",\n        category: \"مهارت‌های ارتباطی\",\n        readTime: \"۸ دقیقه\",\n        date: \"۱۴۰۳/۰۳/۱۰\",\n        slug: \"7-communication-skills-couples\",\n        metaDesc: \"۷ مهارت ارتباطی که هر زوجی باید بداند. چگونه با همسرتان بهتر صحبت کنید و تعارض را سالم حل کنید. از دکتر هما آزادی.\",\n        intro: \"تحقیقات دهه‌ها نشان داده که کیفیت ارتباط، مهم‌ترین عامل رضایت در رابطه زناشویی است. نه شباهت شخصیتی، نه عشق اولیه، نه شرایط مالی — بلکه نحوه صحبت کردن با یکدیگر. خبر خوب این است که ارتباط یک مهارت است و مهارت‌ها یاد گرفته می‌شوند.\",\n        sections: [\n            {\n                heading: \"مهارت ۱: شنیدن فعال\",\n                body: \"شنیدن فعال یعنی تمام توجه خود را به همسرتان بدهید — بدون گوشی، بدون برنامه‌ریزی پاسخ در ذهن. بعد از صحبت همسرتان، قبل از پاسخ دادن، آنچه فهمیده‌اید را به او برگردانید: \\xabاگر درست فهمیدم، می‌گویی که...\\xbb این کار نشان می‌دهد واقعاً گوش می‌دهید و جلوی سوءتفاهم‌های زیادی را می‌گیرد.\"\n            },\n            {\n                heading: \"مهارت ۲: جملات \\xabمن\\xbb به جای \\xabتو\\xbb\",\n                body: \"وقتی بگویید \\xabتو همیشه...\\xbb یا \\xabتو هیچ‌وقت...\\xbb، همسرتان به طور طبیعی وارد حالت دفاعی می‌شود. به جای آن از جملات \\xabمن\\xbb استفاده کنید: \\xabوقتی این اتفاق می‌افتد، من احساس می‌کنم...\\xbb. این قالب ساده نظر را از اتهام به احساس تغییر می‌دهد و دعوا را از چرخه \\xabتهاجم-دفاع\\xbb خارج می‌کند.\"\n            },\n            {\n                heading: \"مهارت ۳: مکث در میانه دعوا\",\n                body: \"وقتی بدن‌تان در حالت استرس شدید است — ضربان قلب بالا، تنفس سریع — مغز قدرت تفکر منطقی را از دست می‌دهد. در این حالت ادامه دعوا فقط آسیب بیشتری می‌زند. یاد بگیرید در این لحظات بگویید: \\xabالان خیلی هیجانی شدم. ۲۰ دقیقه فاصله بگیریم و برگردیم.\\xbb این فرار نیست؛ مدیریت هوشمندانه بحران است.\"\n            },\n            {\n                heading: \"مهارت ۴: تمایز بین انتقاد و شکایت\",\n                body: \"\\xabامروز ظرف‌ها را نشستی\\xbb شکایت است — درباره یک رفتار خاص است. \\xabهیچ‌وقت کمک نمی‌کنی، بی‌مسئولیتی\\xbb انتقاد است — به شخصیت حمله می‌کند. شکایت طبیعی است؛ انتقاد مخرب است. یاد بگیرید درباره رفتارهای خاص صحبت کنید، نه قضاوت شخصیت.\"\n            },\n            {\n                heading: \"مهارت ۵: سؤال کنید به جای فرض\",\n                body: \"یکی از رایج‌ترین خطاهای ارتباطی، فرض کردن نیت همسرمان است. \\xabمی‌دانم چرا این کار را کردی\\xbb اغلب اشتباه است. به جای آن بپرسید: \\xabچرا این کار را کردی؟ کمک می‌کنی بفهمم.\\xbb کنجکاوی به جای قضاوت، دریچه‌های متفاوتی باز می‌کند.\"\n            },\n            {\n                heading: \"مهارت ۶: درباره احساسات صحبت کنید نه نتیجه‌گیری‌ها\",\n                body: \"\\xabاحساس می‌کنم نادیده گرفته می‌شوم\\xbb با \\xabتو مرا نادیده می‌گیری\\xbb دو جمله کاملاً متفاوتند. اولی درباره احساس شماست — کسی نمی‌تواند آن را رد کند. دومی اتهام است که همسرتان را به دفاع وادار می‌کند. از واژه‌های احساسی واقعی استفاده کنید: تنها، نادیده، ناامن، شاد، ممنون.\"\n            },\n            {\n                heading: \"مهارت ۷: تشکر و قدردانی روزانه\",\n                body: \"تحقیقات گاتمن نشان می‌دهد رابطه‌های موفق به ازای هر یک تعامل منفی، پنج تعامل مثبت دارند. این نسبت ۵ به ۱ را \\xabنسبت جادویی\\xbb می‌نامند. یاد بگیرید هر روز چیزهای کوچکی را که همسرتان انجام می‌دهد تشخیص دهید و قدردانی کنید. این عادت ساده رابطه را از هم می‌کند.\"\n            }\n        ],\n        conclusion: \"این مهارت‌ها ساده به نظر می‌رسند اما تمرین می‌خواهند. اگر احساس می‌کنید الگوهای قدیمی خیلی محکم هستند، کمک یک متخصص می‌تواند این تغییرات را سریع‌تر و پایدارتر کند.\",\n        relatedSlugs: [\n            \"signs-need-couple-therapy\",\n            \"why-premarital-counseling-matters\"\n        ]\n    },\n    {\n        id: 5,\n        title: \"چگونه اضطراب را در خانواده مدیریت کنیم؟\",\n        excerpt: \"اضطراب می‌تواند بر کل خانواده تأثیر بگذارد. راهکارهای علمی برای مدیریت آن در این مقاله.\",\n        category: \"خانواده‌درمانی\",\n        readTime: \"۶ دقیقه\",\n        date: \"۱۴۰۳/۰۲/۲۵\",\n        slug: \"managing-anxiety-in-family\",\n        metaDesc: \"راهکارهای علمی برای مدیریت اضطراب در خانواده. تأثیر اضطراب والدین بر فرزندان و روش‌های عملی. مقاله دکتر هما آزادی.\",\n        intro: \"اضطراب مانند سرماخوردگی مسری است — وقتی یکی از اعضای خانواده دچار اضطراب شدید می‌شود، به تدریج فضای کل خانواده را تحت تأثیر می‌گذارد. والدین مضطرب، فرزندان مضطرب می‌پرورند. اما خبر خوب این است که عکس این هم صادق است: با یادگیری مدیریت اضطراب، می‌توان این چرخه را شکست.\",\n        sections: [\n            {\n                heading: \"اضطراب چگونه در خانواده گسترش می‌یابد؟\",\n                body: \"کودکان از روز اول به شدت به حالت‌های احساسی والدین توجه می‌کنند. وقتی والد مضطرب است، کودک این را حس می‌کند — حتی اگر هیچ کلمه‌ای گفته نشود. تحقیقات نشان می‌دهد فرزندان والدین مبتلا به اختلال اضطرابی، خودشان هم بیشتر در معرض اضطراب هستند — هم به دلایل ژنتیکی و هم به دلیل یادگیری الگوهای رفتاری.\"\n            },\n            {\n                heading: \"نشانه‌های اضطراب در خانواده\",\n                body: \"برخی نشانه‌هایی که نشان می‌دهد اضطراب در خانواده جای گرفته: اجتناب مکرر از موقعیت‌های خاص به خاطر \\xabاحتیاط\\xbb؛ نگرانی مداوم و بیان آن به فرزندان؛ حمایت افراطی از فرزند به دلیل ترس؛ واکنش‌های شدید به مشکلات کوچک؛ دعواهای مکرر که با موضوع \\xabامنیت\\xbb مرتبط است.\"\n            },\n            {\n                heading: \"مدیریت اضطراب شخصی — اولین قدم\",\n                body: \"قبل از هر چیز، مدیریت اضطراب خودتان اولویت است. تکنیک‌هایی که علم اثبات کرده: تنفس دیافراگمی (۴ ثانیه دم، ۴ ثانیه نگه داشتن، ۶ ثانیه بازدم)؛ ورزش منظم که یکی از مؤثرترین کاهش‌دهنده‌های اضطراب است؛ محدود کردن مصرف کافئین و اخبار؛ و اگر اضطراب مزمن است، درمان شناختی-رفتاری (CBT).\"\n            },\n            {\n                heading: \"چگونه با فرزندان درباره اضطراب صحبت کنیم؟\",\n                body: \"کودکان باید بدانند که اضطراب یک احساس طبیعی است — نه چیزی خطرناک. وقتی می‌گویید \\xabمی‌ترسم پس نباید این کار را بکنیم\\xbb، ناخواسته به فرزندتان یاد می‌دهید که ترس دلیل کافی برای اجتناب است. به جای آن بگویید: \\xabکمی نگرانم اما می‌دانم که می‌توانم از پسش بربیایم.\\xbb این مدل‌سازی مقابله با اضطراب است.\"\n            },\n            {\n                heading: \"ایجاد محیط امن در خانه\",\n                body: \"خانه باید جایی باشد که کودک (و بزرگسال) بتواند بدون ترس احساساتش را بیان کند. قوانینی که کمک می‌کند: هیچ احساسی \\xabاشتباه\\xbb نیست؛ صحبت درباره ترس‌ها مجاز است؛ کمک خواستن نشانه ضعف نیست؛ و اشتباه کردن بخشی از یادگیری است. این فضای امن بهترین واکسن در برابر اضطراب مزمن است.\"\n            }\n        ],\n        conclusion: \"اضطراب قابل مدیریت است — هم در سطح فردی و هم در سطح خانوادگی. اگر احساس می‌کنید اضطراب در خانواده‌تان جا خوش کرده و با راهکارهای خودیاری بهبود نمی‌یابد، مشاوره با یک روان‌شناس می‌تواند مسیر را کوتاه‌تر کند.\",\n        relatedSlugs: [\n            \"ocd-myths-facts\",\n            \"signs-need-couple-therapy\"\n        ]\n    },\n    {\n        id: 6,\n        title: \"خیانت در رابطه: مسیر بهبود چیست؟\",\n        excerpt: \"خیانت یکی از دردناک‌ترین تجربیات رابطه است. آیا رابطه بعد از خیانت قابل نجات است؟\",\n        category: \"درمان خیانت\",\n        readTime: \"۷ دقیقه\",\n        date: \"۱۴۰۳/۰۲/۱۵\",\n        slug: \"recovery-after-betrayal\",\n        metaDesc: \"آیا رابطه بعد از خیانت قابل نجات است؟ مسیر علمی بهبود بعد از خیانت. چه کسی به درمان نیاز دارد؟ مقاله دکتر هما آزادی.\",\n        intro: \"کشف خیانت یکی از شدیدترین تجربیات عاطفی است که یک انسان می‌تواند تجربه کند. شوک، خشم، غم، بی‌اعتمادی و سردرگمی به طور همزمان می‌آیند. بسیاری از افراد در این لحظه نمی‌دانند چه تصمیمی بگیرند — بمانند یا بروند. این مقاله نه برای قضاوت، بلکه برای کمک به فهم این مسیر پیچیده نوشته شده.\",\n        sections: [\n            {\n                heading: \"واکنش‌های طبیعی بعد از کشف خیانت\",\n                body: \"بعد از کشف خیانت، واکنش‌هایی مانند شوک و بهت، گریه‌های کنترل‌نشده، خشم شدید، بی‌خوابی، کابوس، از دست دادن اشتها، مشکل در تمرکز و احساس پوچی، همه کاملاً طبیعی هستند. تحقیقات نشان می‌دهد بسیاری از افراد بعد از خیانت علائمی شبیه به PTSD (اختلال استرس پس از سانحه) تجربه می‌کنند. این یعنی مغز شما به یک رویداد آسیب‌زا واکنش نشان می‌دهد — نه اینکه \\xabضعیف\\xbb هستید.\"\n            },\n            {\n                heading: \"آیا رابطه بعد از خیانت قابل نجات است؟\",\n                body: \"پاسخ کوتاه: بله، برای بسیاری از زوج‌ها. اما این بستگی دارد به: آیا طرف خیانت‌کننده واقعاً متعهد به تغییر است؟ آیا مسئولیت کامل را می‌پذیرد؟ آیا شفافیت کامل دارد؟ و آیا طرف آسیب‌دیده تمایل به فرآیند بخشش را دارد؟ تحقیقات نشان می‌دهد زوج‌هایی که درمان تخصصی می‌گیرند و هر دو طرف متعهد هستند، اغلب رابطه‌ای عمیق‌تر از قبل از خیانت می‌سازند.\"\n            },\n            {\n                heading: \"مسیر بازسازی اعتماد: چه انتظاری داشته باشیم؟\",\n                body: \"بازسازی اعتماد یک مسیر غیرخطی است — روزهای خوب و بد دارد. طرف خیانت‌کننده باید بداند که صبر و شفافیت مداوم می‌طلبد، نه یک عذرخواهی و فراموش کردن. طرف آسیب‌دیده هم باید بداند که پرسیدن سؤال‌های مکرر در مراحل اولیه طبیعی است اما در نهایت باید تصمیم بگیرد — بخشش کامل یا پایان رابطه. این تصمیم نیاز به زمان دارد.\"\n            },\n            {\n                heading: \"اگر تصمیم به جدایی بگیرم چه؟\",\n                body: \"جدایی بعد از خیانت یک تصمیم کاملاً درست است — اگر این انتخاب شماست. اما حتی اگر تصمیم به جدایی گرفته‌اید، مشاوره فردی می‌تواند کمک کند درد را پردازش کنید، عزت نفس را بازسازی کنید، از کینه مزمن جلوگیری کنید، و آماده شوید که در آینده دوباره به رابطه اعتماد کنید.\"\n            },\n            {\n                heading: \"نقش درمانگر در فرآیند بهبود\",\n                body: \"درمانگر در این مسیر نه قاضی است نه مشاور برای ماندن یا رفتن. درمانگر کمک می‌کند هر دو طرف احساساتشان را امن بیان کنند، ریشه‌های خیانت را بفهمند (نه برای توجیه، بلکه برای پیشگیری از تکرار)، و به هر انتخابی — ماندن یا رفتن — با وضوح و آرامش بیشتری برسند.\"\n            }\n        ],\n        conclusion: \"خیانت پایان داستان نیست — می‌تواند فصل جدیدی باشد، چه در همان رابطه و چه در زندگی جدید. آنچه مهم است این است که این مسیر را تنها نپیمایید. کمک گرفتن در این شرایط یکی از هوشمندانه‌ترین تصمیماتی است که می‌توانید بگیرید.\",\n        relatedSlugs: [\n            \"signs-need-couple-therapy\",\n            \"7-communication-skills-couples\"\n        ]\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(rsc)/./src/lib/articles.ts\n");

